import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';

const client = new BedrockAgentRuntimeClient({ region: 'us-east-1' });

interface SessionState {
  sessionAttributes: Record<string, string>;
}

const invokeVoiceAgent = async (inputText: string, sessionId: string): Promise<string> => {
  const sessionState: SessionState = {
    sessionAttributes: {
      conversationHistory: JSON.stringify([{ role: 'user', content: 'previous turn' }]),
      latencyBudget: '500ms'
    }
  };

  const command = new InvokeAgentCommand({
    agentId: 'YOUR_AGENT_ID',
    agentAliasId: 'YOUR_AGENT_ALIAS',
    sessionId,
    sessionState,
    inputText
  });

  const response = await client.send(command);
  let completion = '';

  for await (const event of response.completion!) {
    const chunk = event.chunk?.bytes?.toString();
    if (chunk) completion += chunk;
  }

  return completion;
};

