import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

const verifyAgentResponse = async (agentResponse: string, sessionState: any, latencyMs: number) => {
  const result = await vex.verify({
    input: {
      sessionId: sessionState.sessionId,
      conversationLength: sessionState.turnCount || 0,
      latencyMs
    },
    output: {
      agentResponse,
      responseLength: agentResponse.length
    },
    policy: {
      latencyBudget: { lt: 300 },
      voiceAppropriateness: {
        prompt: 'Is this response suitable for voice interface? (concise, clear)',
        minScore: 0.9
      },
      sessionContinuity: {
        prompt: `Previous context: ${JSON.stringify(sessionState.history.slice(-3))}\nCurrent response coherent?`,
        minScore: 0.8
      }
    }
  });

  return {
    passed: result.passed,
    safeToSynthesize: result.passed && latencyMs < 300,
    issues: result.issues
  };
};
